allOf.query:
// Source: risk-metrics.registry W297 emissions ingested as a custom log table.
// Assumes a periodic exporter pushes `snapshotGrouped()` to risk_metrics_CL
// with columns: TimeGenerated, name_s, labels_s, value_d.
risk_metrics_CL
| where TimeGenerated > ago(15m)
| where name_s == 'risk.plan_review.audit.verified'
| where labels_s contains 'result=broken'
| summarize total = sum(value_d) by bin(TimeGenerated, 5m)
| where total > 0
